import{_ as s}from"./chunks/model-families.C8D2g9ev.js";import{b as t,I as r,g as o,j as i}from"./chunks/framework.DUo3J_Qe.js";const v=JSON.parse('{"title":"Types d’apprentissage","description":"","frontmatter":{},"headers":[],"relativePath":"fr/learning/concepts/type.md","filePath":"fr/learning/concepts/type.md"}'),n={name:"fr/learning/concepts/type.md"};function a(p,e,l,u,d,c){return r(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="types-d-apprentissage" tabindex="-1">Types d’apprentissage <a class="header-anchor" href="#types-d-apprentissage" aria-label="Permalink to &quot;Types d’apprentissage&quot;">​</a></h1><p><img src="'+s+'" alt="familles de modèles"></p><h2 id="_1-apprentissage-supervise" tabindex="-1">1. Apprentissage supervisé <a class="header-anchor" href="#_1-apprentissage-supervise" aria-label="Permalink to &quot;1. Apprentissage supervisé&quot;">​</a></h2><p>L’apprentissage supervisé repose sur deux concepts clés :</p><ul><li><strong>Données historiques</strong> : on dispose d’exemples passés avec résultats connus.</li><li><strong>Données étiquetées</strong> : chaque exemple possède une sortie ou un label associé.</li></ul><div class="info custom-block"><p class="custom-block-title">👉 Exemple : prédiction du prix d’une maison</p><ul><li>Caractéristiques (features) : surface, nombre de chambres, type de sol, etc.</li><li>Label (étiquette) : prix de vente réel.</li></ul><p>Le modèle apprend à <strong>associer les caractéristiques au prix</strong> à partir des données passées. Lorsqu’une nouvelle maison apparaît, il prédit son prix de vente à partir de ses caractéristiques.</p></div><div class="tip custom-block"><p class="custom-block-title">Deux types de tâches supervisées</p><ol><li><strong>Classification</strong> : prédire une catégorie (valeur discrète)</li></ol><blockquote><p>👉 Exemple : déterminer si une tumeur est <strong>maligne ou bénigne</strong>, ou si un client remboursera ou fera défaut sur son prêt.</p></blockquote><ol start="2"><li><strong>Régression</strong> : prédire une valeur continue</li></ol><blockquote><p>👉 Exemple : prédire le <strong>prix d’une maison</strong>, la consommation d’électricité ou les résultats scolaires.</p></blockquote></div><h2 id="_2-apprentissage-non-supervise" tabindex="-1">2. Apprentissage non supervisé <a class="header-anchor" href="#_2-apprentissage-non-supervise" aria-label="Permalink to &quot;2. Apprentissage non supervisé&quot;">​</a></h2><p>L’apprentissage non supervisé utilise des <strong>données non étiquetées</strong>. Le modèle doit <strong>découvrir lui-même des motifs ou des groupes</strong> dans les données.</p><div class="info custom-block"><p class="custom-block-title">👉 Exemple</p><p><strong>segmenter des clients</strong> en groupes en fonction de leurs comportements d’achat.</p></div><div class="tip custom-block"><p class="custom-block-title">Limite</p><p>Évaluer la performance d’un modèle non supervisé est plus difficile, car il n’y a pas de labels connus au départ.</p></div><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><ol><li><strong>Supervisé</strong> : utiliser des données étiquetées pour prédire un résultat futur.</li><li><strong>Non supervisé</strong> : trouver des motifs dans des données sans labels.</li></ol><table tabindex="0"><thead><tr><th>Type</th><th>Données utilisées</th><th>Objectif</th></tr></thead><tbody><tr><td>Supervisé</td><td>Étiquetées</td><td>Prédire</td></tr><tr><td>Non supervisé</td><td>Non étiquetées</td><td>Découvrir</td></tr><tr><td>Renforcement</td><td>Récompenses</td><td>Décider</td></tr></tbody></table>',14)])])}const b=t(n,[["render",a]]);export{v as __pageData,b as default};
